import "core-js/modules/esnext.iterator.constructor.js";
import "core-js/modules/esnext.iterator.filter.js";
import "core-js/modules/esnext.iterator.map.js";
import { ref, onMounted, computed } from 'vue';
import { useModules } from '@/composables/useModules';
import { useProfileData } from '@/composables/useProfileData';
import useLoading from '@/composables/useLoading';
import profile from '@/api/profile';
import { ElMessage } from 'element-plus';
import { Dialog, DialogPanel, DialogTitle, TransitionChild, TransitionRoot } from '@headlessui/vue';
import { PlusIcon, ExclamationTriangleIcon } from '@heroicons/vue/24/outline';

// 组件导入
import BasicInfo from './components/BasicInfo.vue';
import ResumeStatus from './components/ResumeStatus.vue';
import ModuleList from './components/ModuleList.vue';
import EditWorkExperienceDialog from './dialogs/EditWorkExperienceDialog.vue';
import EditBasicDialog from './dialogs/EditBasicDialog.vue';
import EditJobIntentionDialog from './dialogs/EditJobIntentionDialog.vue';
import EditSocialLinkDialog from './dialogs/EditSocialLinkDialog.vue';
import EditPortfolioDialog from './dialogs/EditPortfolioDialog.vue';
import AIOptimizeDialog from './dialogs/AIOptimizeDialog.vue';
import EditEducationDialog from './dialogs/EditEducationDialog.vue';

// 获取数据相关

export default {
  __name: 'index',
  setup(__props, {
    expose: __expose
  }) {
    __expose();
    const profileLoading = ref(false);
    const profileData = ref(null);
    const completionData = ref(null);
    const bioExpanded = ref(false);
    const showBioExpandButton = ref(false);

    // 使用组合式函数
    const {
      loading: modulesLoading,
      modules,
      fetchModulesData
    } = useModules();
    const {
      fetchCompletionData
    } = useProfileData();

    // 使用 loading 组合式函数
    const {
      loading,
      withLoading
    } = useLoading();

    // 当前编辑的模块
    const currentModule = ref(null);
    const editFormData = ref({});
    const showEditModal = ref(false);

    // 弹窗状态
    const showWorkExperienceDialog = ref(false);
    const showJobIntentionDialog = ref(false);
    const editJobIntentionData = ref({});
    const currentEditData = ref({});
    const showAIOptimizeDialog = ref(false);
    const showEducationDialog = ref(false);
    const editEducationData = ref({});

    // 确认对话框状态
    const showConfirmDialog = ref(false);
    const confirmMessage = ref('');
    const confirmCallback = ref(null);

    // 显示确认对话框
    const showConfirm = (message, callback) => {
      confirmMessage.value = message;
      confirmCallback.value = callback;
      showConfirmDialog.value = true;
    };

    // 处理确认
    const handleConfirm = async () => {
      if (confirmCallback.value) {
        await confirmCallback.value();
      }
      showConfirmDialog.value = false;
    };

    // 布局数据
    const layoutData = ref({});

    // 计算激活的模块
    const activeModules = computed(() => {
      if (!modules.value) return [];
      return modules.value.filter(module => {
        const layout = layoutData.value[module.type];
        return layout?.visible === true;
      }).sort((a, b) => {
        const orderA = layoutData.value[a.type]?.order || 999;
        const orderB = layoutData.value[b.type]?.order || 999;
        return orderA - orderB;
      });
    });

    // 计算未激活的模块
    const inactiveModules = computed(() => {
      if (!modules.value) return [];
      return modules.value.filter(module => {
        const layout = layoutData.value[module.type];
        return layout && layout.visible === false;
      });
    });

    // 初始化数据
    const initData = async () => {
      await withLoading(async () => {
        try {
          // 先初始化空数据结构
          profileData.value = {
            basic_info: {},
            job_intention: {},
            work_experience: [],
            education: [],
            project: [],
            skill: [],
            certificate: [],
            language: [],
            portfolio: [],
            social_link: []
          };

          // 获取布局数据
          const layoutResponse = await profile.getLayout();
          if (layoutResponse.data?.code === 200) {
            layoutData.value = layoutResponse.data.data.layout;
          }

          // 获取模块数据
          await fetchModulesData();

          // 获取档案数据
          const response = await profile.getData();
          if (response.data?.code === 200) {
            profileData.value = response.data.data;
          }

          // 获取完整度数据
          const completenessResponse = await profile.getCompleteness();
          if (completenessResponse.data?.code === 200) {
            completionData.value = completenessResponse.data.data;
          }
        } catch (error) {
          console.error('初始化数据失败:', error);
          ElMessage.error('获取数据失败，请刷新重试');
        }
      });
    };

    // 更新数据
    const handleUpdate = async () => {
      await initData();
    };

    // 处理编辑
    const handleEdit = (type, data) => {
      console.log('处理编辑:', {
        type,
        data
      });
      currentModule.value = {
        type
      };
      editFormData.value = data || {};
      showEditModal.value = true;
    };

    // 处理个人简介展开/收起
    const toggleBioExpand = () => {
      bioExpanded.value = !bioExpanded.value;
    };

    // 处理工作经历提交
    const handleWorkExperienceSubmit = async data => {
      try {
        await withLoading(async () => {
          if (data.id) {
            await profile.updateModule('work_experience', data);
            ElMessage.success('更新成功');
          } else {
            await profile.addModuleItem('work_experience', data);
            ElMessage.success('添加成功');
          }
          showWorkExperienceDialog.value = false;
          await fetchModulesData();
        });
      } catch (error) {
        console.error('保存失败:', error);
        ElMessage.error('保存失败，请稍后重试');
      }
    };

    // 获取模块显示名称
    const getModuleName = type => {
      const moduleNames = {
        basic_info: '基本信息',
        job_intention: '求职意向',
        work_experience: '工作经历',
        education: '教育经历',
        project: '项目经历',
        skill: '专业技能',
        certificate: '证书奖项',
        language: '语言能力',
        portfolio: '作品展示',
        social_link: '社交主页'
      };
      return moduleNames[type] || type;
    };

    // 处理提交
    const handleSubmit = async data => {
      try {
        await withLoading(async () => {
          const type = currentModule.value?.type;
          console.log('提交数据:', {
            type,
            data
          });

          // 处理基本信息提交
          if (type === 'basic_info') {
            const response = await profile.updateModule('basic_info', data);
            if (response.data?.code === 200) {
              ElMessage.success('保存成功');
              showEditModal.value = false;
              // 重新获取数据
              await initData();
            } else {
              throw new Error(response.data?.message || '保存失败');
            }
            return;
          }

          // 处理其他类型的提交
          if (data.id) {
            await profile.updateModule(type, data);
            ElMessage.success('更新成功');
          } else {
            await profile.addModuleItem(type, data);
            ElMessage.success('添加成功');
          }
          showEditModal.value = false;
          await fetchModulesData();
        });
      } catch (error) {
        console.error('保存失败:', error);
        if (error.response) {
          console.error('错误响应:', {
            status: error.response.status,
            statusText: error.response.statusText,
            data: error.response.data,
            errors: error.response.data?.errors,
            headers: error.response.headers
          });
          if (error.response.data?.errors) {
            const errorMessages = Object.entries(error.response.data.errors).map(([field, messages]) => `${field}: ${messages.join(', ')}`).join('\n');
            ElMessage.error(errorMessages);
          } else {
            ElMessage.error(error.response.data?.message || '保存失败，请重试');
          }
        } else if (error.request) {
          console.error('请求未收到响应:', error.request);
          ElMessage.error('网络请求失败，请检查网络连接');
        } else {
          console.error('请求配置错误:', error.message);
          ElMessage.error('保存失败，请重试');
        }
      }
    };

    // 处理添加
    const handleAdd = type => {
      console.log('处理添加:', type);
      currentModule.value = {
        type
      };
      editFormData.value = {}; // 清空表单数据

      // 根据类型显示对应的弹窗
      switch (type) {
        case 'work_experience':
          showWorkExperienceDialog.value = true;
          break;
        case 'education':
          showEducationDialog.value = true;
          break;
        case 'job_intention':
          showJobIntentionDialog.value = true;
          break;
        case 'social_link':
        case 'portfolio':
        default:
          showEditModal.value = true;
          break;
      }
    };

    // 处理移除模块
    const handleModuleRemove = async (type, id) => {
      try {
        if (id) {
          // 删除具体的模块项
          await profile.deleteModuleItem(type, id);
          ElMessage.success('删除成功');
        } else {
          // 更新布局数据，隐藏整个模块
          const currentLayout = layoutData.value[type] || {};
          const layout = {
            order: currentLayout.order || 999,
            visible: false
          };
          // 直接更新指定类型的布局
          await profile.updateLayout(type, layout);

          // 重新获取布局数据
          const response = await profile.getLayout();
          if (response.data?.code === 200) {
            layoutData.value = response.data.data.layout;
          }
        }
        await fetchModulesData();
      } catch (error) {
        console.error('删除失败:', error);
        ElMessage.error('删除失败，请重试');
      }
    };
    const handleJobIntentionSubmit = async data => {
      try {
        await profile.updateModule('job_intention', data);
        ElMessage.success('保存成功');
        showJobIntentionDialog.value = false;
        await fetchModulesData();
      } catch (error) {
        console.error('保存失败:', error);
        ElMessage.error('保存失败，请重试');
      }
    };
    const handleEducationSubmit = async data => {
      try {
        if (data.id) {
          await profile.updateModule('education', data);
        } else {
          await profile.addModuleItem('education', data);
        }
        ElMessage.success('保存成功');
        showEducationDialog.value = false;
        await fetchModulesData();
      } catch (error) {
        console.error('保存失败:', error);
        ElMessage.error('保存失败，请重试');
      }
    };
    const handleAIOptimize = async () => {
      // AI优化逻辑
    };
    const showDeleteConfirmDialog = ref(false);
    const currentDeleteItem = ref(null);
    const showDeleteConfirm = (type, id) => {
      showDeleteConfirmDialog.value = true;
      currentDeleteItem.value = {
        type,
        id
      };
    };
    const closeDeleteConfirm = () => {
      showDeleteConfirmDialog.value = false;
      currentDeleteItem.value = null;
    };

    // 处理添加模块
    const handleAddModule = async type => {
      try {
        // 更新布局数据
        const currentLayout = layoutData.value[type] || {};
        const layout = {
          order: currentLayout.order || 999,
          visible: true
        };
        // 直接更新指定类型的布局
        await profile.updateLayout(type, layout);

        // 重新获取布局数据
        const response = await profile.getLayout();
        if (response.data?.code === 200) {
          layoutData.value = response.data.data.layout;
        }
        await fetchModulesData();
      } catch (error) {
        console.error('添加模块失败:', error);
        ElMessage.error('添加失败，请重试');
      }
    };

    // 初始化
    onMounted(() => {
      initData();
    });
    const __returned__ = {
      profileLoading,
      profileData,
      completionData,
      bioExpanded,
      showBioExpandButton,
      modulesLoading,
      modules,
      fetchModulesData,
      fetchCompletionData,
      loading,
      withLoading,
      currentModule,
      editFormData,
      showEditModal,
      showWorkExperienceDialog,
      showJobIntentionDialog,
      editJobIntentionData,
      currentEditData,
      showAIOptimizeDialog,
      showEducationDialog,
      editEducationData,
      showConfirmDialog,
      confirmMessage,
      confirmCallback,
      showConfirm,
      handleConfirm,
      layoutData,
      activeModules,
      inactiveModules,
      initData,
      handleUpdate,
      handleEdit,
      toggleBioExpand,
      handleWorkExperienceSubmit,
      getModuleName,
      handleSubmit,
      handleAdd,
      handleModuleRemove,
      handleJobIntentionSubmit,
      handleEducationSubmit,
      handleAIOptimize,
      showDeleteConfirmDialog,
      currentDeleteItem,
      showDeleteConfirm,
      closeDeleteConfirm,
      handleAddModule,
      ref,
      onMounted,
      computed,
      get useModules() {
        return useModules;
      },
      get useProfileData() {
        return useProfileData;
      },
      get useLoading() {
        return useLoading;
      },
      get profile() {
        return profile;
      },
      get ElMessage() {
        return ElMessage;
      },
      get Dialog() {
        return Dialog;
      },
      get DialogPanel() {
        return DialogPanel;
      },
      get DialogTitle() {
        return DialogTitle;
      },
      get TransitionChild() {
        return TransitionChild;
      },
      get TransitionRoot() {
        return TransitionRoot;
      },
      get PlusIcon() {
        return PlusIcon;
      },
      get ExclamationTriangleIcon() {
        return ExclamationTriangleIcon;
      },
      BasicInfo,
      ResumeStatus,
      ModuleList,
      EditWorkExperienceDialog,
      EditBasicDialog,
      EditJobIntentionDialog,
      EditSocialLinkDialog,
      EditPortfolioDialog,
      AIOptimizeDialog,
      EditEducationDialog
    };
    Object.defineProperty(__returned__, '__isScriptSetup', {
      enumerable: false,
      value: true
    });
    return __returned__;
  }
};
